function honorarium_claim_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('honorarium_claim_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'name_of_advisor' => Request::val('name_of_advisor', ''),
		'email_advisor' => Request::val('email_advisor', ''),
		'department_of_tih' => Request::val('department_of_tih', ''),
		'bank_account_no' => Request::val('bank_account_no', ''),
		'ifsc_code' => Request::val('ifsc_code', ''),
		'bank_name' => Request::val('bank_name', ''),
		'pan' => Request::val('pan', ''),
		'place_of_work' => Request::val('place_of_work', ''),
		'date' => Request::dateComponents('date', '1'),
		'no_of_hours' => Request::val('no_of_hours', ''),
		'case_reference_email_subject' => Request::val('case_reference_email_subject', ''),
		'activities' => br2nl(Request::val('activities', '')),
		'others_if_any' => br2nl(Request::val('others_if_any', '')),
		'coordinated_by_tih_user' => Request::lookup('coordinated_by_tih_user', ''),
		'payment_date' => Request::dateComponents('payment_date', ''),
		'amount_paid' => Request::val('amount_paid', ''),
		'transaction_details' => Request::val('transaction_details', ''),
		'approval_status' => Request::val('approval_status', 'Under Consideration'),
		'remarks_for_approval' => br2nl(Request::val('remarks_for_approval', 'None')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('honorarium_claim_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		honorarium_claim_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

