function honorarium_claim_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('honorarium_claim_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: honorarium_claim_table_before_delete
	if(function_exists('honorarium_claim_table_before_delete')) {
		$args = [];
		if(!honorarium_claim_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `honorarium_claim_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: honorarium_claim_table_after_delete
	if(function_exists('honorarium_claim_table_after_delete')) {
		$args = [];
		honorarium_claim_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='honorarium_claim_table' AND `pkValue`='{$selected_id}'", $eo);
}

function honorarium_claim_table_update(&$selected_id, &$error_message = '') {
