		'approval_status' => Request::val('approval_status', ''),
		'remarks_for_approval' => br2nl(Request::val('remarks_for_approval', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('honorarium_claim_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: honorarium_claim_table_before_update
	if(function_exists('honorarium_claim_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!honorarium_claim_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'honorarium_claim_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="honorarium_claim_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('honorarium_claim_table', $data['selectedID'], calculated_fields()['honorarium_claim_table']);

	// hook: honorarium_claim_table_after_update
	if(function_exists('honorarium_claim_table_after_update')) {
		if($row = getRecord('honorarium_claim_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!honorarium_claim_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('honorarium_claim_table', $selected_id);
}

